interface ProfileRow {
  id: number;
  trade_name: string;
  legal_name_public_policy: string;
  business_start_date: string | null;
  tax_office: string | null;
  blue_return_enabled: number;
  invoice_registration_number: string | null;
  created_at: string;
  updated_at: string;
