+    if (productId == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    if (!getProduct(app, productId)) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+
+    try {
+      const payload = normalizeCreatePlan({ ...((req.body ?? {}) as PlanPayload), productId });
+      const created = app.db.transaction(() => {
+        const result = app.db
