+
+    const deleteProduct = await app.inject({ method: 'DELETE', url: `/api/products/${productId}` });
+    expect(deleteProduct.statusCode).toBe(204);
+
+    const missing = await app.inject({ method: 'GET', url: `/api/products/${productId}` });
