+          .run(payload);
+        const product = getProductOrThrow(app, Number(result.lastInsertRowid));
+        writeAudit(app, 'product', 'create', product.id, undefined, product);
+        return product;
+      })();
+      reply.code(201);
+      return created;
+    } catch (error) {
+      reply.code(400);
+      return invalidPayload(error);
+    }
+  });
+
+  app.put('/api/products/:id', async (req, reply) => {
