+  if (!getProduct(db, next.productId)) {
+    throw new Error(`product not found: ${next.productId}`);
+  }
+
+  const run = db.transaction(() => {
+    db.prepare(
+      `UPDATE subscription_plans SET
+         product_id = @productId,
