+import { describe, expect, it } from 'vitest';
+import { bootstrap } from '../src/db/bootstrap.js';
+import {
+  checkProductCompleteness,
+  createProduct,
+  createSubscriptionPlan,
+  deleteProduct,
+  deleteSubscriptionPlan,
+  getProduct,
+  getSubscriptionPlan,
+  listProducts,
