+    expect(listSubscriptionPlansForProduct(db, product.id)).toHaveLength(1);
+    expect(getSubscriptionPlan(db, plan.id)?.planName).toBe('月額');
+
+    const updated = updateSubscriptionPlan(db, plan.id, {
+      planName: '月額スタンダード',
