+    expect(audits.map((row) => row.action)).toEqual(['create', 'update', 'delete']);
+
+    db.close();
+  });
+
+  it('returns warnings for missing product page fields and subscription conditions', () => {
+    const product = {
+      productType: 'membership',
+      priceTaxIncluded: 1200.25,
