+import { describe, expect, it } from 'vitest';
+import { bootstrap } from '../src/db/bootstrap.js';
+import {
+  checkProductCompleteness,
+  createProduct,
+  createSubscriptionPlan,
+  deleteProduct,
+  deleteSubscriptionPlan,
+  getProduct,
+  getSubscriptionPlan,
+  listProducts,
+  listSubscriptionPlansForProduct,
+  updateProduct,
+  updateSubscriptionPlan,
+  type Product,
+  type SubscriptionPlan,
+} from '../src/services/products.js';
+
+describe('product service', () => {
+  it('creates, lists, gets, updates, and deletes products with audit logs', () => {
+    const db = bootstrap({ filename: ':memory:' });
+
+    const created = createProduct(db, {
+      sku: 'FW-TPL-001',
+      title: '業務テンプレート',
+      productType: 'template',
+      priceTaxIncluded: 3300,
+      licenseSummary: '1名の事業利用可',
+      operatingEnvironment: 'Excel 2021以降',
+      refundPolicy: 'デジタル商品のため提供後返金不可',
+      status: 'active',
+    });
+    expect(created).toMatchObject({
+      id: expect.any(Number),
+      sku: 'FW-TPL-001',
+      title: '業務テンプレート',
+      priceTaxIncluded: 3300,
+      currency: 'JPY',
+      createdAt: expect.any(String),
+    });
+    expect(listProducts(db)).toHaveLength(1);
+    expect(getProduct(db, created.id)?.sku).toBe('FW-TPL-001');
+
+    const updated = updateProduct(db, created.id, {
+      title: '業務テンプレートPro',
+      priceTaxIncluded: 4400,
+      refundPolicy: null,
+    });
+    expect(updated).toMatchObject({
+      id: created.id,
+      title: '業務テンプレートPro',
+      priceTaxIncluded: 4400,
+      refundPolicy: null,
+    });
+
+    expect(() =>
+      createProduct(db, {
+        sku: 'BAD-PRICE',
+        title: 'Bad',
+        productType: 'download',
+        priceTaxIncluded: 100.5,
+      }),
+    ).toThrow(/integer yen/);
+
+    expect(deleteProduct(db, created.id)).toBe(true);
+    expect(getProduct(db, created.id)).toBeNull();
+
+    const audits = db
+      .prepare(
+        `SELECT action, entity_type, entity_id, before_json, after_json
+         FROM audit_logs
+         WHERE entity_type = ?
+         ORDER BY id ASC`,
+      )
+      .all('product') as Array<{
+      action: string;
+      entity_type: string;
+      entity_id: string;
+      before_json: string | null;
+      after_json: string | null;
+    }>;
+    expect(audits.map((row) => row.action)).toEqual(['create', 'update', 'delete']);
+    expect(audits.every((row) => row.entity_id === String(created.id))).toBe(true);
+    expect(JSON.parse(audits[0]?.after_json ?? '{}')).toMatchObject({ sku: 'FW-TPL-001' });
+    expect(JSON.parse(audits[1]?.before_json ?? '{}')).toMatchObject({ priceTaxIncluded: 3300 });
+    expect(JSON.parse(audits[1]?.after_json ?? '{}')).toMatchObject({ priceTaxIncluded: 4400 });
+    expect(JSON.parse(audits[2]?.before_json ?? '{}')).toMatchObject({ title: '業務テンプレートPro' });
+
+    db.close();
+  });
+
+  it('creates, lists, gets, updates, and deletes subscription plans with audit logs', () => {
+    const db = bootstrap({ filename: ':memory:' });
+    const product = createProduct(db, {
+      sku: 'FW-MEM-001',
+      title: '月額会員',
+      productType: 'membership',
+      priceTaxIncluded: 1980,
+    });
+
+    const plan = createSubscriptionPlan(db, {
+      productId: product.id,
+      planName: '月額',
+      billingPeriod: 'monthly',
+      renewalPolicy: '毎月1日に税込1,980円を請求',
+      cancellationPolicy: '次回更新日前日までに会員画面で解約',
+      postCancelAccessPolicy: '解約月末まで閲覧可能',
+    });
+    expect(plan).toMatchObject({
+      id: expect.any(Number),
+      productId: product.id,
+      planName: '月額',
+      billingPeriod: 'monthly',
+    });
+    expect(listSubscriptionPlansForProduct(db, product.id)).toHaveLength(1);
+    expect(getSubscriptionPlan(db, plan.id)?.planName).toBe('月額');
+
+    const updated = updateSubscriptionPlan(db, plan.id, {
+      planName: '月額スタンダード',
+      trialPolicy: '14日間無料',
+    });
+    expect(updated).toMatchObject({ id: plan.id, planName: '月額スタンダード', trialPolicy: '14日間無料' });
+
+    expect(deleteSubscriptionPlan(db, plan.id)).toBe(true);
+    expect(getSubscriptionPlan(db, plan.id)).toBeNull();
+
+    const audits = db
+      .prepare('SELECT action FROM audit_logs WHERE entity_type = ? ORDER BY id ASC')
+      .all('subscription_plan') as Array<{ action: string }>;
+    expect(audits.map((row) => row.action)).toEqual(['create', 'update', 'delete']);
+
+    db.close();
+  });
+
+  it('returns warnings for missing product page fields and subscription conditions', () => {
+    const product = {
+      productType: 'membership',
+      priceTaxIncluded: 1200.25,
+      licenseSummary: '',
+      operatingEnvironment: null,
+      refundPolicy: undefined,
+    } as unknown as Product;
+    const plan = {
+      billingPeriod: 'monthly',
+      renewalPolicy: '',
+      cancellationPolicy: null,
+      postCancelAccessPolicy: ' ',
+    } as unknown as SubscriptionPlan;
+
+    const result = checkProductCompleteness(product, [plan]);
+
+    expect(result.complete).toBe(false);
+    expect(result.warnings.map((warning) => warning.field)).toEqual([
+      'priceTaxIncluded',
+      'operatingEnvironment',
+      'licenseSummary',
+      'refundPolicy',
+      'plans[0].renewalPolicy',
+      'plans[0].cancellationPolicy',
+      'plans[0].postCancelAccessPolicy',
+    ]);
+    expect(result.warnings.every((warning) => warning.reason.includes('S'))).toBe(true);
+  });
+
+  it('returns no warnings when product page fields and subscription conditions are complete', () => {
+    const product = {
+      productType: 'membership',
+      priceTaxIncluded: 1200,
+      licenseSummary: '1契約1名まで利用可能',
+      operatingEnvironment: 'Chrome最新版、macOS 14以降またはWindows 11',
+      refundPolicy: '初回決済から7日以内は返金可',
+    } as Product;
+    const plan = {
+      billingPeriod: 'monthly',
+      renewalPolicy: '毎月契約日に税込1,200円で自動更新',
+      cancellationPolicy: '更新日前日までに会員画面から解約',
+      postCancelAccessPolicy: '解約後も当月末まで閲覧可',
+    } as SubscriptionPlan;
+
+    expect(checkProductCompleteness(product, [plan])).toEqual({ complete: true, warnings: [] });
+  });
+});
diff --git a/packages/server/src/routes/products.ts b/packages/server/src/routes/products.ts
new file mode 100755
index 0000000000000000000000000000000000000000..c85049ec14ac136f5dab21da7d058efcfa954d06
--- /dev/null
+++ b/packages/server/src/routes/products.ts
@@ -0,0 +1,619 @@
+import type { FastifyInstance } from 'fastify';
+
+type ProductType = 'download' | 'course' | 'membership' | 'template' | 'service' | 'other';
+type BillingPeriod = 'monthly' | 'yearly' | 'one_time' | 'other';
+
+interface ProductRow {
+  id: number;
+  sku: string;
+  title: string;
+  product_type: ProductType;
+  price_tax_included: number;
+  currency: string;
+  license_summary: string | null;
+  operating_environment: string | null;
+  refund_policy: string | null;
+  status: string;
+  created_at: string;
+}
+
+interface SubscriptionPlanRow {
+  id: number;
+  product_id: number;
+  plan_name: string;
+  billing_period: BillingPeriod;
+  renewal_policy: string | null;
+  cancellation_policy: string | null;
+  trial_policy: string | null;
+  post_cancel_access_policy: string | null;
+  created_at: string;
+}
+
+interface ProductPayload {
+  sku?: unknown;
+  title?: unknown;
+  productType?: unknown;
+  priceTaxIncluded?: unknown;
+  currency?: unknown;
+  licenseSummary?: unknown;
+  operatingEnvironment?: unknown;
+  refundPolicy?: unknown;
+  status?: unknown;
+}
+
+interface PlanPayload {
+  productId?: unknown;
+  planName?: unknown;
+  billingPeriod?: unknown;
+  renewalPolicy?: unknown;
+  cancellationPolicy?: unknown;
+  trialPolicy?: unknown;
+  postCancelAccessPolicy?: unknown;
+}
+
+const PRODUCT_TYPES: ProductType[] = ['download', 'course', 'membership', 'template', 'service', 'other'];
+const BILLING_PERIODS: BillingPeriod[] = ['monthly', 'yearly', 'one_time', 'other'];
+
+export async function productRoutes(app: FastifyInstance): Promise<void> {
+  app.get('/api/products', async () => {
+    return listProducts(app);
+  });
+
+  app.get('/api/products/:id', async (req, reply) => {
+    const id = routeId(req.params);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const product = getProduct(app, id);
+    if (!product) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    return product;
+  });
+
+  app.post('/api/products', async (req, reply) => {
+    try {
+      const body = (req.body ?? {}) as ProductPayload;
+      const payload = normalizeCreateProduct(body);
+      const created = app.db.transaction(() => {
+        const result = app.db
+          .prepare(
+            `INSERT INTO products
+              (sku, title, product_type, price_tax_included, currency, license_summary,
+               operating_environment, refund_policy, status)
+             VALUES
+              (@sku, @title, @productType, @priceTaxIncluded, @currency, @licenseSummary,
+               @operatingEnvironment, @refundPolicy, @status)`,
+          )
+          .run(payload);
+        const product = getProductOrThrow(app, Number(result.lastInsertRowid));
+        writeAudit(app, 'product', 'create', product.id, undefined, product);
+        return product;
+      })();
+      reply.code(201);
+      return created;
+    } catch (error) {
+      reply.code(400);
+      return invalidPayload(error);
+    }
+  });
+
+  app.put('/api/products/:id', async (req, reply) => {
+    const id = routeId(req.params);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const before = getProduct(app, id);
+    if (!before) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+
+    try {
+      const next = { ...before, ...normalizeUpdateProduct((req.body ?? {}) as ProductPayload) };
+      const updated = app.db.transaction(() => {
+        app.db
+          .prepare(
+            `UPDATE products SET
+               sku = @sku,
+               title = @title,
+               product_type = @productType,
+               price_tax_included = @priceTaxIncluded,
+               currency = @currency,
+               license_summary = @licenseSummary,
+               operating_environment = @operatingEnvironment,
+               refund_policy = @refundPolicy,
+               status = @status
+             WHERE id = @id`,
+          )
+          .run({
+            id,
+            sku: next.sku,
+            title: next.title,
+            productType: next.productType,
+            priceTaxIncluded: next.priceTaxIncluded,
+            currency: next.currency,
+            licenseSummary: next.licenseSummary,
+            operatingEnvironment: next.operatingEnvironment,
+            refundPolicy: next.refundPolicy,
+            status: next.status,
+          });
+        const after = getProductOrThrow(app, id);
+        writeAudit(app, 'product', 'update', id, before, after);
+        return after;
+      })();
+      return updated;
+    } catch (error) {
+      reply.code(400);
+      return invalidPayload(error);
+    }
+  });
+
+  app.delete('/api/products/:id', async (req, reply) => {
+    const id = routeId(req.params);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const before = getProduct(app, id);
+    if (!before) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    app.db.transaction(() => {
+      const plans = listPlansForProduct(app, id);
+      writeAudit(app, 'product', 'delete', id, { ...before, plans }, undefined);
+      app.db.prepare('DELETE FROM products WHERE id = ?').run(id);
+    })();
+    reply.code(204);
+    return undefined;
+  });
+
+  app.get('/api/products/:id/plans', async (req, reply) => {
+    const productId = routeId(req.params);
+    if (productId == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    if (!getProduct(app, productId)) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    return listPlansForProduct(app, productId);
+  });
+
+  app.post('/api/products/:id/plans', async (req, reply) => {
+    const productId = routeId(req.params);
+    if (productId == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    if (!getProduct(app, productId)) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+
+    try {
+      const payload = normalizeCreatePlan({ ...((req.body ?? {}) as PlanPayload), productId });
+      const created = app.db.transaction(() => {
+        const result = app.db
+          .prepare(
+            `INSERT INTO subscription_plans
+              (product_id, plan_name, billing_period, renewal_policy, cancellation_policy,
+               trial_policy, post_cancel_access_policy)
+             VALUES
+              (@productId, @planName, @billingPeriod, @renewalPolicy, @cancellationPolicy,
+               @trialPolicy, @postCancelAccessPolicy)`,
+          )
+          .run(payload);
+        const plan = getPlanOrThrow(app, Number(result.lastInsertRowid));
+        writeAudit(app, 'subscription_plan', 'create', plan.id, undefined, plan);
+        return plan;
+      })();
+      reply.code(201);
+      return created;
+    } catch (error) {
+      reply.code(400);
+      return invalidPayload(error);
+    }
+  });
+
+  app.put('/api/products/:productId/plans/:planId', async (req, reply) => {
+    const productId = routeParamId(req.params, 'productId');
+    const planId = routeParamId(req.params, 'planId');
+    if (productId == null || planId == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    if (!getProduct(app, productId)) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    const before = getPlan(app, planId);
+    if (!before || before.productId !== productId) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+
+    try {
+      const next = { ...before, ...normalizeUpdatePlan((req.body ?? {}) as PlanPayload), productId };
+      const updated = app.db.transaction(() => {
+        app.db
+          .prepare(
+            `UPDATE subscription_plans SET
+               product_id = @productId,
+               plan_name = @planName,
+               billing_period = @billingPeriod,
+               renewal_policy = @renewalPolicy,
+               cancellation_policy = @cancellationPolicy,
+               trial_policy = @trialPolicy,
+               post_cancel_access_policy = @postCancelAccessPolicy
+             WHERE id = @id`,
+          )
+          .run({
+            id: planId,
+            productId: next.productId,
+            planName: next.planName,
+            billingPeriod: next.billingPeriod,
+            renewalPolicy: next.renewalPolicy,
+            cancellationPolicy: next.cancellationPolicy,
+            trialPolicy: next.trialPolicy,
+            postCancelAccessPolicy: next.postCancelAccessPolicy,
+          });
+        const after = getPlanOrThrow(app, planId);
+        writeAudit(app, 'subscription_plan', 'update', planId, before, after);
+        return after;
+      })();
+      return updated;
+    } catch (error) {
+      reply.code(400);
+      return invalidPayload(error);
+    }
+  });
+
+  app.delete('/api/products/:productId/plans/:planId', async (req, reply) => {
+    const productId = routeParamId(req.params, 'productId');
+    const planId = routeParamId(req.params, 'planId');
+    if (productId == null || planId == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const before = getPlan(app, planId);
+    if (!before || before.productId !== productId) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    app.db.transaction(() => {
+      writeAudit(app, 'subscription_plan', 'delete', planId, before, undefined);
+      app.db.prepare('DELETE FROM subscription_plans WHERE id = ?').run(planId);
+    })();
+    reply.code(204);
+    return undefined;
+  });
+
+  app.get('/api/products/:id/completeness', async (req, reply) => {
+    const id = routeId(req.params);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const product = getProduct(app, id);
+    if (!product) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    const plans = listPlansForProduct(app, id);
+    return { product, plans, ...checkCompleteness(product, plans) };
+  });
